parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "score": {
      "type": "number",
      "description": "Score from 0 to 100"
    },
    "decision": {
      "type": "string",
      "enum": ["accept", "reject", "borderline"],
      "description": "Final decision"
    },
    "reason": {
      "type": "string",
      "description": "Brief explanation of the scoring decision"
    }
  },
  "required": ["score", "decision", "reason"]
}

parameters.text:
